import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import {headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, MyTable, mainStageHeaderStrings} from "../../utils";
import { routeNamesInventory } from '../../routeNames';
import { stockStrings } from '../config';
import { stockActions } from '../actions';
import { TableCell, Switch } from '@material-ui/core';
import StockStageHeader from './StockStageHeader';

const style = theme => ({
    root: {
        marginTop : 20,
    },
    cell : {
        padding :5,
        minWidth : "2cm"
    }
})
class _Stocks extends Component {
    constructor(props) {
        super(props);
        this.state = { 
            lastId : null,
            rows : null,
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "STOCKS",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Stocks", path : routeNamesInventory.stocks},
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                StockStageHeader
            ],
            [mainStageHeaderStrings.buttons] : [
                {value : "New Stock", onClick : ()=>props.history.push(routeNamesInventory.newStock)}
            ]
        })(dispatch);

        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            dispatch,
            [stockStrings.stockCategories] : stockCategories,
            [stockStrings.itemForms] : itemForms,
            [stockStrings.itemPackages] : itemPackages,
            [stockStrings.stores] : stores
        } = this.props;
        
        if(!stockCategories) stockActions.getStockCategories()(dispatch);
        if(!itemForms) stockActions.getItemFroms()(dispatch);
        if(!itemPackages) stockActions.getItemPackages()(dispatch);
        if(!stores) stockActions.getStores()(dispatch);

        const {lastId, rows } = this.state;
        stockActions.getStocks(lastId, rows)(dispatch);

    }
    cellMapFormat = ({row, cellMap}) => {
        const {
            classes,
            [stockStrings.stockCategories] : stockCategories,
            [stockStrings.itemForms] : itemForms,
            [stockStrings.itemPackages] : itemPackages,
        } = this.props;
        if(typeof cellMap === "number"){
            if(row && row.stockInfo){
                const {item : stockItem} = row.stockInfo.getFirstObjectByPropValue("storeId", cellMap);
                return stockItem ? 
                    <TableCell className={classes.cell}>{
                        stockItem && stockItem.stock && stockItem.stock.map((item, index)=>{
                            if(itemPackages){
                                const {item : packageItem} = itemPackages.getFirstObjectByPropValue("_id", item.packageId);
                                if(packageItem){
                                    return <div key={index}><strong style={{color : "gray"}}>{packageItem.name}: </strong>{item.count}</div>
                                } else return null;
                            }else return null; 
                        })   
                    }</TableCell> : null
            }else return null;
        }else{
            switch(cellMap){
                case "active" : 

                    return <TableCell className={classes.cell}>
                        <Switch size="small"/>
                    </TableCell>
                case "exIncome" : 
                    let income = 0;
                    try{
                        income += parseInt(row.stockInDSU) * parseInt(row.sellingPrice);
                    }catch(e){
                        //handle error
                    }
                    return <TableCell className={classes.cell}>
                        {income.toLocaleString()}
                    </TableCell>;
                case "defaultIU" :
                case "defaultSU" : 
                    let sellingUnit = null;
                    if(row.defaultSU && row.defaultSU){
                        const packageId = row.defaultSU.packageId;
                        const {item : sellingUnitItem} = itemPackages.getFirstObjectByPropValue("_id", packageId) || {};
                        if(sellingUnitItem){
                            sellingUnit = sellingUnitItem.name;
                        }
                    }
                    return <TableCell className={classes.cell}>
                        {sellingUnit}
                    </TableCell>
                case "stockInDSU" : 
                case "stockInDIU" : return <TableCell className={classes.cell}>
                    {Number(row[cellMap]).toLocaleString()}
                </TableCell>
                case "sPrice" : return <TableCell className={classes.cell}>
                    {Number(row.sellingPrice).toLocaleString()}
                </TableCell>
                case "pPrice" : return <TableCell className={classes.cell}>
                    {Number(row.purchasePrice).toLocaleString()}
                </TableCell>
                case "categoryId" : 
                    if(!stockCategories) return <TableCell className={classes.cell}/>;
                    let category = null;
                    if(stockCategories){
                        const {item : catItem} = stockCategories.getFirstObjectByPropValue("_id", row.item.categoryId);
                        if(catItem) category = catItem.name;
                    }
                    return <TableCell className={classes.cell}>
                        {category}
                    </TableCell>
                case "formId" : 
                    if(!itemForms) return <TableCell className={classes.cell}/>;
                    let form = null;
                    if(itemForms){
                        const {item : formItem} = itemForms.getFirstObjectByPropValue("_id", row.item.formId);
                        if(formItem) form = formItem.name;
                    }
                    return <TableCell className={classes.cell}>
                        {form}
                    </TableCell>
                case "brand" : return <TableCell className={classes.cell}>
                    {row.item.brand}
                </TableCell>
                case "itemId" : return <TableCell className={classes.cell}>
                    {row.item.name}
                </TableCell>
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }
    }
    generateTableHeader(editMode){
        const {
            [stockStrings.stores] : stores
        } = this.props;
        let header = [
            {name : "ID", dataMap : "_id"}, 
            {name : "Item", dataMap : "itemId"}, 
            {name : "Form", dataMap : "formId"}, 
            {name : "Brand", dataMap : "brand"}, 
            {name : "Category", dataMap : "categoryId"}];
        if(stores){
            let dataInfo = {name : "Store Stocks", subHeads : []};
            for (let i = 0; i < stores.length; i++) {
                const storeInfo = stores[i];
                dataInfo.subHeads.push(storeInfo._id);
            }
            header.push(dataInfo);
        }
        header.push(
            {name : "DIU", dataMap : "defaultIU"}, 
            {name : "DSU", dataMap : "defaultSU"}, 
            {name : "Stock in DIU", dataMap : "stockInDIU"}, 
            {name : "Stock in DSU", dataMap : "stockInDSU"}, 
            {name : "Purchase Price", dataMap : "pPrice"}, 
            {name : "Selling Price", dataMap : "sPrice"},
            {name :"Ex. Income", dataMap : "exIncome"});
        if(editMode) header.push(
            {name :"Active", dataMap : "active"},
        );
        return header;
    }
    subHeaderMap = (subHead)=>{
        const {
            [stockStrings.stores] : stores
        } = this.props;
        if(stores){
            const {item} = stores.getFirstObjectByPropValue("_id", subHead) || {};
            return item ? item.name : null;
        }
        return null;
    }
    render() {
        const {
            classes,
            [stockStrings.stocks] : stocks,
            [stockStrings.stockEditMode] : editMode
        } = this.props;
        console.log(this.props);
        let header = this.generateTableHeader(editMode);        
        return (
            <div className={classes.root}>
                <MyTable //SU = selling unit
                    multiRowHeader={header}
                    subHeaderMap={this.subHeaderMap.bind(this)}
                    dataMapIndicator="dataMap"
                    subheaderIndicator="subHeads"
                    data={stocks}
                    CellMap={this.cellMapFormat.bind(this)}/>
            </div>
        );
    }
}


_Stocks.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({stockReducer}) => ({
    [stockStrings.stocks] : stockReducer[stockStrings.stocks],
    [stockStrings.stockCategories] : stockReducer[stockStrings.stockCategories],
    [stockStrings.itemForms] : stockReducer[stockStrings.itemForms],
    [stockStrings.itemPackages] : stockReducer[stockStrings.itemPackages],
    [stockStrings.stores] : stockReducer[stockStrings.stores],
    [stockStrings.stockEditMode] : stockReducer[stockStrings.stockEditMode],
})


export const Stocks = connect(mapStateToProps)(withStyles(style)(_Stocks));
export {Stocks as default}