import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { DefaultMainStageHeader } from "../../utils";
import { stockStrings } from '../config';
import { stockActions } from '../actions';


const style = theme => ({
    root: {
    }
})
class _StockStageHeader extends Component {
    cancelEditHandler = () => {        
        stockActions.setStockEditMode(false)(this.props.dispatch);
    }
    editBtnHandler = ( ) => {
        const {
            dispatch,
            [stockStrings.stockEditMode] : stockEditMode
        } = this.props;
        if(stockEditMode){
            //do something
        }
        stockActions.setStockEditMode(!Boolean(stockEditMode))(dispatch);
    }
    render() {
        const {
            classes,
            [stockStrings.stockEditMode] : stockEditMode
        } = this.props;
        return (
            <DefaultMainStageHeader
                cancelEditHandler={this.cancelEditHandler.bind(this)}
                editBtnHandler={this.editBtnHandler.bind(this)}
                editMode={stockEditMode}
                />
        );
    }
}


_StockStageHeader.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({stockReducer}) => ({
    [stockStrings.stockEditMode] : stockReducer[stockStrings.stockEditMode],
})


export const StockStageHeader = connect(mapStateToProps)(withStyles(style)(_StockStageHeader));
export {StockStageHeader as default}